// ALPHA AGGREGATOR 
const trades = $('Binance Trades (Raw)').first().json || [];
const liqs = $('Binance Liquidations (Raw)').first().json || [];

let whaleBlocks = [];
if (Array.isArray(trades)) {
  whaleBlocks = trades
    .map(t => {
      const price = parseFloat(t.price);
      const qty = parseFloat(t.qty);
      const totalValue = price * qty;
      return { price, qty, totalValue, type: t.isBuyerMaker ? 'SELL' : 'BUY', time: t.time };
    })
    .filter(t => t.totalValue >= 500000)
    .sort((a, b) => b.time - a.time)
    .slice(0, 5)
    .map(t => `${t.type} ${t.qty.toFixed(2)} BTC at $${t.price.toLocaleString('en-US')} ($${(t.totalValue / 1e6).toFixed(2)}M)`)
    .join(' | ');
}
if (!whaleBlocks || whaleBlocks.length === 0) whaleBlocks = "No singular block trades over $500k detected.";

let liqSummary = "No recent liquidation clusters detected.";
if (Array.isArray(liqs) && liqs.length > 0) {
  let longLiq = 0;
  let shortLiq = 0;
  liqs.forEach(l => {
    const val = parseFloat(l.p) * parseFloat(l.q);
    if (l.S === 'BUY') shortLiq += val;
    if (l.S === 'SELL') longLiq += val;
  });
  const dominant = longLiq > shortLiq ? "LONGS" : "SHORTS";
  const totalFlushed = ((longLiq + shortLiq) / 1e6).toFixed(2);
  if (totalFlushed > 0) {
    liqSummary = `Recent Structural Flush: $${totalFlushed}M wiped. Dominant cascade: ${dominant}. (Longs flushed: $${(longLiq / 1e6).toFixed(2)}M, Shorts flushed: $${(shortLiq / 1e6).toFixed(2)}M).`;
  }
}

return [{
  json: {
    whale_blocks: whaleBlocks,
    liquidation_data: liqSummary
  }
}];

// ALPHA WHALE PROMPT
const alphaData = $('Alpha Data Aggregator').first().json || {};
const rawLiqData = alphaData.liquidation_data || "No data";
const recentBlocks = alphaData.whale_blocks || "No data";

const promptText = `ROLE: You are the ALPHA TELEMETRY ENGINE for an elite macro trading terminal.
TASK: Analyze raw orderbook and liquidation data and output strict, terminal-grade JSON.
TONE: Clinical, robotic, highly precise. Use exact numbers.

RAW DATA:
- Liquidation Clusters: ${rawLiqData}
- Recent Whale Executions: ${recentBlocks}

OUTPUT REQUIREMENT:
Generate valid JSON matching this exact structure. Do NOT wrap in markdown.
{
  "flush_detection": {
    "cumulative_leverage": "Numeric value (e.g., $142.4M)",
    "support_margin_lower": "Price (e.g., $72,300)",
    "support_margin_upper": "Price (e.g., $72,550)",
    "analysis": "1 sentence describing the cascade velocity event."
  },
  "whale_blocks": [
    {
      "timestamp": "HH:MM:SS",
      "asset": "BTCUSDT",
      "type": "SHORT SWEEP or LIMIT BID WALL or BLOCK TWAP",
      "size": "Volume + Asset (e.g., 420.50 BTC)",
      "venue": "BINANCE FUTURES or COINBASE PRO"
    }
  ]
}`;

return [{
  json: {
    model: 'meta-llama/llama-3.1-8b-instruct:free', 
    messages: [{ role: 'user', content: promptText }],
    temperature: 0.3,
    response_format: { type: "json_object" }
  }
}];

// AUTOPSY / RESOLUTION BRAIN
// Fetch from main workflow nodes
let pastSignals = [];
try { pastSignals = $('Read signals.json').first().json.ledger || []; } catch(e) {}
let currentMarket = {};
try { currentMarket = $('Chaos Pre-Processor v5').first().json || {}; } catch(e) {}

const openSignals = pastSignals.filter(s => s.status === 'OPEN' || s.status === 'PENDING').slice(0, 5);
if (openSignals.length === 0) {
  return [{ json: { skip: True, message: "No open signals" } }];
}

const promptText = `ROLE: You are the AUTOPSY / RESOLUTION ENGINE.
TASK: Review previously issued trading signals against current market prices. Grade them as WIN, LOSS, or OPEN.
CURRENT MARKET: BTC: ${currentMarket.btcPrice || 'N/A'}
PAST SIGNALS:
${JSON.stringify(openSignals, null, 2)}

OUTPUT REQUIREMENT:
JSON array with keys: signal_hash, status, close_price, pnl_percent, autopsy_note`;

return [{
  json: {
    model: 'google/gemini-2.5-flash',
    messages: [{ role: 'user', content: promptText }],
    temperature: 0.1,
    response_format: { type: "json_object" }
  }
}];

// GEOPOLITICAL WIRES BRAIN
let articles = [];
try { articles = $('ContextNews').first().json.articles || []; } catch(e) {}
if (articles.length === 0) return [{ json: { skip: true } }];

const rawNews = articles.slice(0, 15).map(a => `[${a.source?.name || 'Wire'}] ${a.title}`).join('\n');

const promptText = `ROLE: CHIEF MACRO STRATEGIST.
TASK: Extract 3 critical events moving liquidity today.
RAW HEADLINES:
${rawNews}

OUTPUT REQUIREMENT:
Strict JSON format:
{
  "intel_wires": [{ "source": "", "title": "", "impact": "", "forces": [] }]
}`;

return [{
  json: {
    model: 'anthropic/claude-3.5-sonnet', 
    messages: [{ role: 'user', content: promptText }],
    temperature: 0.4,
    response_format: { type: "json_object" }
  }
}];
